 3→import java.io.File;
 4→import java.io.IOException;
 5→
 6→/**
 7→ * A class for running a test suite. Encapsulates the ability to run the test suite on a
 8→ * reference implementation to generate the expected results, the ability to create a
 9→ * "wrapper" file for comparing actual results to these expected results, and the ability
10→ * to run the test suite on a set of files and identify which test cases each file fails
11→ * on.
12→ */
13→public class Tester {
14→    // TODO: complete the definition of the Tester class here
15→
16→    /**
17→     * The absolute path to the directory containing the student implementations.
18→     */
19→    private String implDirPath;
20→
21→    /**
22→     * Helper function for deleting all cached Python files, so that an old cached version
23→     * of expected.pyc doesn't accidentally get invoked.
24→     *
25→     * @throws IOException if the path to the pycache is invalid or a deletion operation
26→     *                     fails
27→     */
28→    private void deletePyCache() throws IOException {
29→        // Get the list of all files in the pycache
30→        File pyCacheDir = new File(this.implDirPath + "/__pycache__/");
31→        String[] filepaths = pyCacheDir.list();
32→
33→        if (filepaths != null) {
34→            for (String filepath : filepaths) {
35→                // Only delete .pyc files
36→                if (filepath.contains(".pyc")) {
37→                    File cachedFile =
38→                            new File(this.implDirPath + "/__pycache__/" + filepath);
39→                    if (!cachedFile.delete()) {
40→                        throw new IOException("could not delete cached file " + filepath);
41→                    }
42→                }
43→            }
44→        }
45→    }
46→}

