41→        listNode.setExDomain(Arrays.asList(1));
42→
43→        Set<PyListObj<PyIntObj>> result = listNode.genExVals();
44→        assertEquals(2, result.size());
45→        assertTrue(result.contains(new PyListObj<>(Arrays.asList(new PyIntObj(1)))));
