package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract class whose subclasses represent domains of possible values for
 * a single Python type. Each node can generate exhaustive and random values.
 *
 * @param <ObjType> the type of Python object generated by this node
 */
public abstract class APyNode<ObjType extends APyObj> {

    /**
     * The exhaustive domain for this node.
     */
    protected List<?> exDomain;

    /**
     * The random domain for this node.
     */
    protected List<?> ranDomain;

    /**
     * Returns the exhaustive domain for this node.
     *
     * @return the exhaustive domain
     */
    public List<?> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param domain the exhaustive domain
     */
    public void setExDomain(List<?> domain) {
        this.exDomain = domain;
    }

    /**
     * Returns the random domain for this node.
     *
     * @return the random domain
     */
    public List<?> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the random domain for this node.
     *
     * @param domain the random domain
     */
    public void setRanDomain(List<?> domain) {
        this.ranDomain = domain;
    }

    /**
     * Generates and returns all possible values in the exhaustive domain.
     *
     * @return the set of all exhaustive values
     */
    public abstract Set<ObjType> genExVals();

    /**
     * Generates and returns a single random value from the random domain.
     *
     * @return a random value
     */
    public abstract ObjType genRandVal();
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.HashSet;
import java.util.Random;
import java.util.Set;

/**
 * A node for generating Python int values.
 */
public class PyIntNode extends APyNode<PyIntObj> {

    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new HashSet<>();
        for (Object val : this.exDomain) {
            result.add(new PyIntObj((Integer) val));
        }
        return result;
    }

    @Override
    public PyIntObj genRandVal() {
        Random rand = new Random();
        int idx = rand.nextInt(this.ranDomain.size());
        return new PyIntObj((Integer) this.ranDomain.get(idx));
    }
}

