package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * A class for generating a base set of test cases from a list of node specifications.
 * Combines exhaustive test generation (Cartesian product) with random test generation.
 */
public class BaseSetGenerator {

    /**
     * The nodes representing the argument domains.
     */
    private final List<APyNode<?>> nodes;

    /**
     * The number of random tests to generate.
     */
    private final int numRand;

    /**
     * Constructor for a BaseSetGenerator.
     *
     * @param nodes   the nodes representing argument domains
     * @param numRand the number of random tests to generate
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Generates all exhaustive test cases (Cartesian product of all nodes' exhaustive values).
     *
     * @return the set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        List<Set<? extends APyObj>> allVals = new ArrayList<>();
        for (APyNode<?> node : nodes) {
            allVals.add(node.genExVals());
        }

        Set<TestCase> result = new HashSet<>();
        cartesianProduct(allVals, 0, new ArrayList<>(), result);
        return result;
    }

    /**
     * Generates random test cases that are not duplicates of exhaustive test cases.
     *
     * @param numTests the number of random tests to generate
     * @return the set of random test cases
     */
    public Set<TestCase> genRandTests(int numTests) {
        Set<TestCase> exTests = genExTests();
        Set<TestCase> randTests = new HashSet<>();
        int maxAttempts = numTests * 100;
        int attempts = 0;

        while (randTests.size() < numTests && attempts < maxAttempts) {
            List<APyObj> args = new ArrayList<>();
            for (APyNode<?> node : nodes) {
                args.add(node.genRandVal());
            }
            TestCase tc = new TestCase(args);
            if (!exTests.contains(tc)) {
                randTests.add(tc);
            }
            attempts++;
        }
        return randTests;
    }

    /**
     * Generates the combined base set: all exhaustive tests plus the specified number
     * of unique random tests (not duplicating exhaustive tests).
     *
     * @return a list containing all exhaustive and random test cases
     */
    public List<TestCase> genBaseSet() {
        Set<TestCase> exTests = genExTests();
        Set<TestCase> randTests = new HashSet<>();
        int maxAttempts = this.numRand * 100;
        int attempts = 0;

        while (randTests.size() < this.numRand && attempts < maxAttempts) {
            List<APyObj> args = new ArrayList<>();
            for (APyNode<?> node : nodes) {
                args.add(node.genRandVal());
            }
            TestCase tc = new TestCase(args);
            if (!exTests.contains(tc)) {
                randTests.add(tc);
            }
            attempts++;
        }

        List<TestCase> result = new ArrayList<>(exTests);
        result.addAll(randTests);
        return result;
    }

    /**
     * Recursively computes the Cartesian product of all value sets.
     */
    private void cartesianProduct(List<Set<? extends APyObj>> allVals, int depth,
                                  List<APyObj> current, Set<TestCase> result) {
        if (depth == allVals.size()) {
            result.add(new TestCase(new ArrayList<>(current)));
            return;
        }
        for (APyObj val : allVals.get(depth)) {
            current.add(val);
            cartesianProduct(allVals, depth + 1, current, result);
            current.remove(current.size() - 1);
        }
    }
}

